const newTreeSha = $input.first().json.sha;
const parentSha = $('Build Main Tree Request2').first().json.parent_commit_sha;
const message = $('Build Main Tree Request2').first().json.commit_message;
return [{
  json: {
    body: {
      message: message,
      tree: newTreeSha,
      parents: [parentSha]
    }
  }
}];

const cleanData = $('Remove Draft Frontmatter2').first().json;
const branchInfo = $input.first().json;
const parentCommitSha = branchInfo.commit.sha;
const currentTreeSha = branchInfo.commit.commit.tree.sha;
const defaultBranch = cleanData.default_branch || $('Get Repo Info2').first().json.default_branch;

return [{
  json: {
    body: {
      base_tree: currentTreeSha,
      tree: [
        { path: 'recipes/en/' + cleanData.en_filename, mode: '100644', type: 'blob', content: cleanData.en_content },
        { path: 'recipes/es/' + cleanData.es_filename, mode: '100644', type: 'blob', content: cleanData.es_content }
      ]
    },
    parent_commit_sha: parentCommitSha,
    commit_message: cleanData.commit_message,
    default_branch: defaultBranch,
    chat_id: cleanData.chat_id,
    recipeName: cleanData.recipeName
  }
}];

const callbackData = $('Parse Callback & Build Resume URL1').first().json;

if (!callbackData.en_filename || !callbackData.es_filename) {
  throw new Error('Missing draft recipe data. Generate the recipe again and approve from the latest message.');
}

function removeDraft(content) {
  if (typeof content !== 'string') return '';
  return content.replace(/^---\ndraft: true\n/, '---\n');
}

return [{
  json: {
    en_filename: callbackData.en_filename,
    en_content: removeDraft(callbackData.en_content),
    es_filename: callbackData.es_filename,
    es_content: removeDraft(callbackData.es_content),
    commit_message: callbackData.commit_message,
    default_branch: callbackData.default_branch || 'main',
    chat_id: callbackData.chat_id || null,
    recipeName: callbackData.recipeName || null
  }
}];

const data = $('Build Preview URL2').first().json;
const text = '<b>🍳 New Recipe Draft: ' + data.recipeName + '</b>

A new recipe has been generated and is ready for your review on the preview site.

<b>Preview:</b>
' + data.previewUrl;
return [{ json: { text } }];

const draftData = $('Inject Draft Frontmatter2').first().json;
const repoInfo = $('Get Repo Info2').first().json;
const slug = draftData.recipe_slug;
const previewUrl = 'https://lowkeycooking-blog-git-drafts-christophcharafs-projects.vercel.app/en/recipes/' + slug;
const recipeName = slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');

const approveCb = 'pub|approve';
const rejectCb = 'pub|reject';

const store = $getWorkflowStaticData('global');
if (!store.publishApprovalSessions) store.publishApprovalSessions = {};
store.publishApprovalSessions[String(draftData.chat_id)] = {
  recipe_name: recipeName,
  recipe_slug: slug,
  en_filename: draftData.en_filename,
  en_content: draftData.en_content,
  es_filename: draftData.es_filename,
  es_content: draftData.es_content,
  commit_message: draftData.commit_message,
  default_branch: repoInfo.default_branch || 'main',
  updated_at: new Date().toISOString()
};

return [{ json: { previewUrl, recipeName, chat_id: draftData.chat_id, approve_cb: approveCb, reject_cb: rejectCb } }];

const newTreeSha = $input.first().json.sha;
const parentSha = $('Build Create Tree Request3').first().json.parent_commit_sha;
const message = $('Build Create Tree Request3').first().json.commit_message;

return [{
  json: {
    body: {
      message: message,
      tree: newTreeSha,
      parents: [parentSha]
    }
  }
}];

const draftData = $('Inject Draft Frontmatter2').first().json;
const branchInfo = $input.first().json;
const parentCommitSha = branchInfo.commit.sha;
const currentTreeSha = branchInfo.commit.commit.tree.sha;

return [{
  json: {
    body: {
      base_tree: currentTreeSha,
      tree: [
        {
          path: 'recipes/en/' + draftData.en_filename,
          mode: '100644',
          type: 'blob',
          content: draftData.en_content
        },
        {
          path: 'recipes/es/' + draftData.es_filename,
          mode: '100644',
          type: 'blob',
          content: draftData.es_content
        }
      ]
    },
    parent_commit_sha: parentCommitSha,
    commit_message: draftData.commit_message,
    default_branch: 'drafts'
  }
}];

const prepareData = $input.first().json;

function addDraft(content) {
  return content.replace(/^---\n/, '---\ndraft: true\n');
}

const slug = prepareData.en_filename.replace('.md', '');

return [{
  json: {
    en_filename: prepareData.en_filename,
    en_content: addDraft(prepareData.en_content),
    es_filename: prepareData.es_filename,
    es_content: addDraft(prepareData.es_content),
    commit_message: prepareData.commit_message,
    recipe_slug: slug,
    chat_id: prepareData.chat_id
  }
}];

const items = $input.all();
const en = items.find(i => i.json.lang === 'en');
const es = items.find(i => i.json.lang === 'es');

if (!en || !es) {
  throw new Error('Missing language variant. Got: ' + JSON.stringify(items.map(i => i.json.lang)));
}

const recipeName = en.json.filename.replace('.md', '');
const chatId = en.json.chat_id || es.json.chat_id;

return [{
  json: {
    en_filename: en.json.filename,
    en_content: en.json.content,
    es_filename: es.json.filename,
    es_content: es.json.content,
    commit_message: 'feat: add ' + recipeName + ' recipe (EN + ES)',
    chat_id: chatId
  }
}];

const raw = $input.first().json.text;
const chatId = $('Get Recipe Data2').first().json.chat_id;

let content = raw
  .replace(/^```(?:markdown|md)?\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

const filenameMatch = content.match(/<!--\s*filename:\s*([\w-]+\.md)\s*-->/);
const filename = filenameMatch ? filenameMatch[1] : 'recipe-' + Date.now() + '.md';

const cleanContent = content
  .replace(/<!--\s*filename:[^>]+-->\n?/, '')
  .trim();

return [{ json: { filename, content: cleanContent, lang: 'es', chat_id: chatId } }];

const raw = $input.first().json.text;
const chatId = $('Get Recipe Data2').first().json.chat_id;

let content = raw
  .replace(/^```(?:markdown|md)?\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

const filenameMatch = content.match(/<!--\s*filename:\s*([\w-]+\.md)\s*-->/);
const filename = filenameMatch ? filenameMatch[1] : 'recipe-' + Date.now() + '.md';

const cleanContent = content
  .replace(/<!--\s*filename:[^>]+-->\n?/, '')
  .trim();

return [{ json: { filename, content: cleanContent, lang: 'en', chat_id: chatId } }];

const baseData = $input.first().json;
const query = $json.query || {};

const recipeName = baseData.recipe_name;
const unsplashUrls = Array.isArray(baseData.unsplash_urls) ? baseData.unsplash_urls : [];
const source = (query.source || baseData.current_source || 'unsplash').toString();
const idx = Number.parseInt(query.idx ?? baseData.current_index ?? 0, 10);
const seed = (query.seed || baseData.current_seed || '').toString();
const fallbackFoodImage = 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=1200&q=80';

const pollinationsKey = 'sk_kDELuAwOIQELSZp2jvTTWPqUwFW17Fz3';
const aiAvailable = pollinationsKey.length > 0;

const prompt = encodeURIComponent(
  'professional food photography ' + recipeName + ' delicious appetizing styled dish overhead shot'
);
const makeAiImageUrl = (aiSeed) => {
  if (!aiAvailable) return '';
  return (
    'https://image.pollinations.ai/prompt/' +
    prompt +
    '?width=1200&height=800&nologo=true&model=flux&seed=' +
    aiSeed +
    '&key=' +
    encodeURIComponent(pollinationsKey)
  );
};
const createSafeSeed = () => String(Math.floor(Math.random() * 2147483647) + 1);
const sanitizeSeed = (value) => {
  const parsed = Number.parseInt(String(value || ''), 10);
  if (Number.isFinite(parsed) && parsed >= 1 && parsed <= 2147483647) {
    return String(parsed);
  }
  return createSafeSeed();
};

let imageUrl;
if (source === 'unsplash' && unsplashUrls.length > 0) {
  const safeIndex = Number.isFinite(idx)
    ? ((idx % unsplashUrls.length) + unsplashUrls.length) % unsplashUrls.length
    : 0;
  imageUrl = unsplashUrls[safeIndex];
} else if (source === 'ai') {
  const aiSeed = sanitizeSeed(seed);
  imageUrl = makeAiImageUrl(aiSeed) || baseData.image_url || fallbackFoodImage;
} else {
  imageUrl = baseData.image_url || unsplashUrls[0] || fallbackFoodImage;
}

return [{
  json: {
    recipe_name: recipeName,
    image_url: imageUrl,
    chat_id: baseData.chat_id
  }
}];

const baseData = $input.first().json;
const recipeName = baseData.recipe_name;
const fallbackFoodImage = 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=1200&q=80';
const pollinationsKey = 'sk_kDELuAwOIQELSZp2jvTTWPqUwFW17Fz3';
const aiAvailable = pollinationsKey.length > 0;

if (!aiAvailable) {
  return [{
    json: {
      ...baseData,
      image_url: baseData.image_url || fallbackFoodImage,
      current_source: baseData.current_source || 'unsplash',
      current_seed: '',
      ai_available: false,
      image_warning: 'AI image requires a configured API key.'
    }
  }];
}

const prompt = encodeURIComponent(
  'professional food photography ' + recipeName + ' delicious appetizing styled dish overhead shot'
);
const seed = String(Math.floor(Math.random() * 2147483647) + 1);
const imageUrl =
  'https://image.pollinations.ai/prompt/' +
  prompt +
  '?width=1200&height=800&nologo=true&model=flux&seed=' +
  seed +
  '&key=' +
  encodeURIComponent(pollinationsKey);

return [{
  json: {
    ...baseData,
    image_url: imageUrl,
    current_source: 'ai',
    current_index: 0,
    current_seed: seed,
    ai_available: true,
    image_warning: ''
  }
}];

const baseData = $input.first().json;
const query = $json.query || {};

const recipeName = baseData.recipe_name;
const chatId = baseData.chat_id;
const unsplashUrls = Array.isArray(baseData.unsplash_urls) ? baseData.unsplash_urls : [];
const idx = Number.parseInt(query.idx ?? baseData.current_index ?? 0, 10);
const createSafeSeed = () => String(Math.floor(Math.random() * 2147483647) + 1);
const fallbackFoodImage = 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=1200&q=80';
const pollinationsKey = 'sk_kDELuAwOIQELSZp2jvTTWPqUwFW17Fz3';
const aiAvailable = pollinationsKey.length > 0;

if (unsplashUrls.length === 0) {
  const prompt = encodeURIComponent(
    'professional food photography ' + recipeName + ' delicious appetizing styled dish overhead shot'
  );
  const seed = createSafeSeed();
  const imageUrl = aiAvailable
    ? (
      'https://image.pollinations.ai/prompt/' +
      prompt +
      '?width=1200&height=800&nologo=true&model=flux&seed=' +
      seed +
      '&key=' +
      encodeURIComponent(pollinationsKey)
    )
    : fallbackFoodImage;

  return [{
    json: {
      ...baseData,
      recipe_name: recipeName,
      chat_id: chatId,
      image_url: imageUrl,
      current_source: aiAvailable ? 'ai' : 'fallback',
      current_index: 0,
      current_seed: aiAvailable ? seed : '',
      ai_available: aiAvailable,
      image_warning: aiAvailable ? '' : 'AI image requires a configured API key.'
    }
  }];
}

const safeIdx = Number.isFinite(idx) ? idx : 0;
const nextIndex = (safeIdx + 1 + unsplashUrls.length) % unsplashUrls.length;

return [{
  json: {
    ...baseData,
    recipe_name: recipeName,
    chat_id: chatId,
    image_url: unsplashUrls[nextIndex],
    current_source: 'unsplash',
    current_index: nextIndex,
    current_seed: '',
    ai_available: aiAvailable,
    image_warning: ''
  }
}];

const data = $input.first().json;

const source = (data.current_source || 'unsplash').toString();
const index = Number.isFinite(Number(data.current_index)) ? Number(data.current_index) : 0;
const seed = (data.current_seed || '').toString();
const aiAvailable = !!data.ai_available;
const warning = (data.image_warning || '').toString();

const totalUnsplash = Array.isArray(data.unsplash_urls) ? data.unsplash_urls.length : 0;
let imageCaption = source === 'unsplash'
  ? 'Pick image (' + (index + 1) + '/' + Math.max(totalUnsplash, 1) + ')'
  : source === 'ai'
    ? 'Pick AI image'
    : 'Pick image';

if (!aiAvailable) {
  imageCaption += '\n(AI unavailable)';
}
if (warning) {
  imageCaption += '\n' + warning;
}

const callbackPayload = (action) => {
  const safeSeed = (seed || '').replace(/\|/g, '').slice(0, 20);
  return ['img', action, source, String(index), safeSeed].join('|');
};

const store = $getWorkflowStaticData('global');
if (!store.imagePickerSessions) store.imagePickerSessions = {};
store.imagePickerSessions[String(data.chat_id)] = {
  recipe_name: data.recipe_name,
  chat_id: data.chat_id,
  unsplash_urls: Array.isArray(data.unsplash_urls) ? data.unsplash_urls : [],
  image_url: data.image_url,
  current_source: source,
  current_index: index,
  current_seed: seed,
  ai_available: aiAvailable,
  image_warning: warning,
  updated_at: new Date().toISOString()
};

return [{
  json: {
    recipe_name: data.recipe_name,
    image_url: data.image_url,
    chat_id: data.chat_id,
    unsplash_urls: data.unsplash_urls || [],
    current_source: source,
    current_index: index,
    current_seed: seed,
    ai_available: aiAvailable,
    image_warning: warning,
    image_caption: imageCaption,
    approve_cb: callbackPayload('approve'),
    next_cb: callbackPayload('next'),
    ai_cb: callbackPayload('ai'),
    cancel_cb: callbackPayload('cancel')
  }
}];

const results = $input.first().json.results || [];
const recipeName = $('Validate Recipe Name2').first().json.recipe_name;
const chatId = $('Validate Recipe Name2').first().json.chat_id;
const fallbackFoodImage = 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=1200&q=80';

const pollinationsKey = 'sk_kDELuAwOIQELSZp2jvTTWPqUwFW17Fz3';
const aiAvailable = pollinationsKey.length > 0;

const unsplashUrls = results
  .map((item) => item?.urls?.regular)
  .filter(Boolean)
  .map((url) => url.split('?')[0] + '?w=1200&q=80');

const prompt = encodeURIComponent(
  'professional food photography ' + recipeName + ' delicious appetizing styled dish overhead shot'
);
const makeAiImageUrl = (seed) => {
  if (!aiAvailable) return '';
  return (
    'https://image.pollinations.ai/prompt/' +
    prompt +
    '?width=1200&height=800&nologo=true&model=flux&seed=' +
    seed +
    '&key=' +
    encodeURIComponent(pollinationsKey)
  );
};
const createSafeSeed = () => String(Math.floor(Math.random() * 2147483647) + 1);

let imageUrl = '';
let currentSource = 'unsplash';
let currentIndex = 0;
let currentSeed = '';
let imageWarning = '';

if (unsplashUrls.length > 0) {
  imageUrl = unsplashUrls[0];
} else {
  currentSeed = createSafeSeed();
  const aiUrl = makeAiImageUrl(currentSeed);

  if (aiUrl) {
    currentSource = 'ai';
    imageUrl = aiUrl;
  } else {
    currentSource = 'fallback';
    currentSeed = '';
    imageUrl = fallbackFoodImage;
    imageWarning = 'AI image requires a configured API key.';
  }
}

return [{
  json: {
    recipe_name: recipeName,
    chat_id: chatId,
    unsplash_urls: unsplashUrls,
    image_url: imageUrl,
    current_source: currentSource,
    current_index: currentIndex,
    current_seed: currentSeed,
    ai_available: aiAvailable,
    image_warning: imageWarning
  }
}];

const msg = $json.message;
const text = ((msg && msg.text) || '').trim();
const chatId = msg && msg.chat && msg.chat.id;

const allowedCommands = ['/recipe', '/generate'];

if (!text) {
  return [{
    json: {
      valid: false,
      error: 'empty',
      recipe_name: '',
      chat_id: chatId,
      allowed_commands: allowedCommands
    }
  }];
}

if (!text.startsWith('/')) {
  return [{
    json: {
      valid: false,
      error: 'missing_command',
      recipe_name: '',
      chat_id: chatId,
      allowed_commands: allowedCommands
    }
  }];
}

const parts = text.split(/\s+/).filter(Boolean);
const command = (parts[0] || '').toLowerCase();

if (!allowedCommands.includes(command)) {
  return [{
    json: {
      valid: false,
      error: 'invalid_command',
      recipe_name: '',
      chat_id: chatId,
      command,
      allowed_commands: allowedCommands
    }
  }];
}

const recipeName = parts.slice(1).join(' ').trim();
if (!recipeName) {
  return [{
    json: {
      valid: false,
      error: 'missing_recipe_name',
      recipe_name: '',
      chat_id: chatId,
      command,
      allowed_commands: allowedCommands
    }
  }];
}

return [{
  json: {
    valid: true,
    recipe_name: recipeName,
    chat_id: chatId,
    command,
    allowed_commands: allowedCommands
  }
}];

const cq = $json.callback_query || {};
const data = String(cq.data || '');
const chatId = cq?.message?.chat?.id;

const parts = data.split('|');
const type = parts[0];

if (!chatId || (type !== 'img' && type !== 'pub')) {
  return [{
    json: {
      ok: false,
      reason: 'Unsupported callback payload',
      chat_id: chatId || null
    }
  }];
}

const store = $getWorkflowStaticData('global');

if (type === 'img') {
  if (parts.length < 5) {
    return [{ json: { ok: false, reason: 'Invalid image callback payload', chat_id: chatId } }];
  }

  const action = parts[1];
  const source = parts[2] || 'unsplash';
  const idx = Number.parseInt(parts[3] || '0', 10);
  const seed = parts[4] || '';

  const sessions = store.imagePickerSessions || {};
  const session = sessions[String(chatId)] || null;

  if (!session?.recipe_name) {
    return [{
      json: {
        ok: false,
        reason: 'No active image picker session for this chat. Send a recipe name again.',
        chat_id: chatId
      }
    }];
  }

  const safeIdx = Number.isFinite(idx) ? idx : 0;

  return [{
    json: {
      ok: true,
      callback_type: 'image',
      query: {
        action,
        source,
        idx: safeIdx,
        seed
      },
      chat_id: chatId,
      callback_id: cq.id,
      recipe_name: session.recipe_name,
      unsplash_urls: Array.isArray(session.unsplash_urls) ? session.unsplash_urls : [],
      image_url: session.image_url,
      current_source: session.current_source || 'unsplash',
      current_index: Number.isFinite(Number(session.current_index)) ? Number(session.current_index) : 0,
      current_seed: session.current_seed || '',
      ai_available: !!session.ai_available,
      image_warning: session.image_warning || ''
    }
  }];
}

if (parts.length < 2) {
  return [{ json: { ok: false, reason: 'Invalid publish callback payload', chat_id: chatId } }];
}

const action = parts[1];
const publishSessions = store.publishApprovalSessions || {};
const session = publishSessions[String(chatId)] || null;

if (!session?.recipe_slug) {
  return [{
    json: {
      ok: false,
      reason: 'No active publish approval session for this chat. Generate a recipe first.',
      chat_id: chatId
    }
  }];
}

return [{
  json: {
    ok: true,
    callback_type: 'publish',
    query: { action },
    chat_id: chatId,
    callback_id: cq.id,
    recipeName: session.recipe_name,
    recipe_slug: session.recipe_slug,
    en_filename: session.en_filename,
    en_content: session.en_content,
    es_filename: session.es_filename,
    es_content: session.es_content,
    commit_message: session.commit_message,
    default_branch: session.default_branch || 'main'
  }
}];
